DDL:
DROP TABLE IF EXISTS FACT_AGRICULTURE_OPERATIONS CASCADE;
CREATE TABLE FACT_AGRICULTURE_OPERATIONS (
	AGRICULTURE_OPERATIONS_ID BIGINT PRIMARY KEY,
	GEOGRAPHY_ID BIGINT,
	CROP_INCOME_HOUSEHOLD_RUPEES DOUBLE PRECISION,
	INCOME_FROM_CROPS_MINUS_EXPENSES DOUBLE PRECISION,
	INCOME_FROM_LAND_RENTED_OR_SHARECROPPED_OUT_RUPEES DOUBLE PRECISION,
	INCOME_FROM_AGRICULTURE_MINUS_EXPENSES DOUBLE PRECISION,
	FOREIGN KEY (GEOGRAPHY_ID) REFERENCES DIM_GEOGRAPHY (GEOGRAPHY_ID)
);

DROP TABLE IF EXISTS FACT_HOUSEHOLD_CONSUMPTION_DEBT CASCADE;
CREATE TABLE FACT_HOUSEHOLD_CONSUMPTION_DEBT (
	HOUSEHOLD_CONSUMPTION_DEBT_ID BIGINT PRIMARY KEY,
	GEOGRAPHY_ID BIGINT,
	TOTAL_HOUSEHOLD_CONSUMPTION_EXPENDITURE DOUBLE PRECISION,
	LARGEST_LOAN_AMOUNT_RUPEES DOUBLE PRECISION,
	OUTSTANDING_HOUSEHOLD_DEBT_RUPEES DOUBLE PRECISION,
	CREDIT_DUE_TO_HOUSEHOLD BIGINT,
	FOREIGN KEY (GEOGRAPHY_ID) REFERENCES DIM_GEOGRAPHY (GEOGRAPHY_ID)
);

DROP TABLE IF EXISTS FACT_WAGE_REMITTANCE_INCOME CASCADE;
CREATE TABLE FACT_WAGE_REMITTANCE_INCOME (
	WAGE_REMITTANCE_INCOME_ID BIGINT PRIMARY KEY,
	GEOGRAPHY_ID BIGINT,
	ANNUAL_HOUSEHOLD_WAGE_INCOME_RUPEES DOUBLE PRECISION,
	REMITTANCES_RECEIVED_FROM_NONRESIDENT_RELATIVES_RUPEES DOUBLE PRECISION,
	INCOME_FROM_SALARY_POSITION BIGINT,
	FOREIGN KEY (GEOGRAPHY_ID) REFERENCES DIM_GEOGRAPHY (GEOGRAPHY_ID)
);

DROP TABLE IF EXISTS FACT_CAPITAL_TRANSACTIONS CASCADE;
CREATE TABLE FACT_CAPITAL_TRANSACTIONS (
	CAPITAL_TRANSACTIONS_ID BIGINT PRIMARY KEY,
	GEOGRAPHY_ID BIGINT,
	INCOME_SALE_NON_AGRICULTURAL_LAND_RUPEES DOUBLE PRECISION,
	INCOME_SALE_AGRICULTURAL_LAND_RUPEES DOUBLE PRECISION,
	FOREIGN KEY (GEOGRAPHY_ID) REFERENCES DIM_GEOGRAPHY (GEOGRAPHY_ID)
);
